import React, { useState, useEffect, useCallback } from 'react';
import { alertsAPI } from '../utils/api';
import RiskBadge from '../components/RiskBadge';

export default function AlertsPage({ liveEvents, onAlertCountChange }) {
  const [alerts, setAlerts]   = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter]   = useState('unread');
  const [toast, setToast]     = useState('');

  const fetchAlerts = useCallback(async () => {
    try {
      const params = {};
      if (filter === 'unread') params.acknowledged = false;
      if (filter === 'read')   params.acknowledged = true;
      const r = await alertsAPI.list(params);
      setAlerts(r.data.alerts);
      if (filter !== 'read') onAlertCountChange?.(r.data.alerts.filter(a => !a.is_acknowledged).length);
    } finally { setLoading(false); }
  }, [filter, onAlertCountChange]);

  useEffect(() => { fetchAlerts(); }, [fetchAlerts]);
  useEffect(() => { if (liveEvents?.length) fetchAlerts(); }, [liveEvents, fetchAlerts]);

  const ack = async (id) => { await alertsAPI.acknowledge(id); fetchAlerts(); };
  const ackAll = async () => { await alertsAPI.acknowledgeAll(); setToast('ALL ALERTS ACKNOWLEDGED'); setTimeout(() => setToast(''), 3000); fetchAlerts(); };

  const unread = alerts.filter(a => !a.is_acknowledged).length;

  const sevColor = { critical: 'var(--accent-red)', high: '#ff6600', medium: 'var(--accent-amber)', low: 'var(--accent-blue)' };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '18px' }}>
      {toast && (
        <div className="animate-slide-in-right" style={{ position: 'fixed', top: '20px', right: '20px', zIndex: 200, background: 'rgba(0,255,136,0.1)', border: '1px solid rgba(0,255,136,0.4)', color: 'var(--accent-green)', fontFamily: "'Space Mono', monospace", fontSize: '10px', letterSpacing: '0.1em', padding: '10px 16px' }}>
          ✓ {toast}
        </div>
      )}

      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <div>
          <div style={{ fontFamily: "'Space Mono', monospace", fontSize: '9px', color: 'var(--text-dim)', letterSpacing: '0.2em', marginBottom: '4px' }}>MODULE // ALT-001</div>
          <h1 style={{ fontSize: '22px', fontWeight: '700', color: 'var(--text-primary)' }}>Threat Alerts</h1>
        </div>
        {unread > 0 && (
          <button className="btn btn-primary" onClick={ackAll}>✓ CLEAR ALL ({unread})</button>
        )}
      </div>

      {/* Filter tabs */}
      <div style={{ display: 'flex', gap: '4px' }}>
        {['unread', 'read', 'all'].map(f => (
          <button key={f} onClick={() => setFilter(f)} style={{
            fontFamily: "'Space Mono', monospace", fontSize: '9px', letterSpacing: '0.12em',
            padding: '8px 16px', border: '1px solid', cursor: 'pointer', transition: 'all 0.15s', textTransform: 'uppercase',
            background: filter === f ? 'rgba(0,212,255,0.1)' : 'transparent',
            borderColor: filter === f ? 'rgba(0,212,255,0.5)' : 'var(--border-dim)',
            color: filter === f ? 'var(--accent-blue)' : 'var(--text-dim)',
          }}>
            {f === 'unread' ? `UNREAD${unread ? ` [${unread}]` : ''}` : f === 'read' ? 'ACKNOWLEDGED' : 'ALL'}
          </button>
        ))}
      </div>

      {/* Alert list */}
      {loading ? (
        <div style={{ textAlign: 'center', padding: '60px', color: 'var(--text-muted)', fontFamily: "'JetBrains Mono', monospace", fontSize: '11px' }}>LOADING ALERTS...</div>
      ) : !alerts.length ? (
        <div style={{ background: 'var(--bg-panel)', border: '1px solid var(--border-dim)', padding: '60px', textAlign: 'center' }}>
          <div style={{ fontSize: '32px', marginBottom: '12px', color: 'var(--accent-green)' }}>✓</div>
          <div style={{ fontFamily: "'Space Mono', monospace", fontSize: '11px', color: 'var(--accent-green)', letterSpacing: '0.15em', marginBottom: '6px' }}>NO ACTIVE THREATS</div>
          <div style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '10px', color: 'var(--text-muted)' }}>
            {filter === 'unread' ? 'All alerts have been acknowledged' : 'No alerts in this category'}
          </div>
        </div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
          {alerts.map(a => {
            const c = sevColor[a.severity] || sevColor.medium;
            return (
              <div key={a.id} className="animate-slide-in-up" style={{
                background: a.is_acknowledged ? 'var(--bg-panel)' : 'var(--bg-card)',
                border: `1px solid ${a.is_acknowledged ? 'var(--border-dim)' : `${c}40`}`,
                position: 'relative', overflow: 'hidden',
                opacity: a.is_acknowledged ? 0.6 : 1,
                transition: 'all 0.2s',
              }}>
                {/* Severity stripe */}
                {!a.is_acknowledged && <div style={{ position: 'absolute', left: 0, top: 0, bottom: 0, width: '3px', background: c }} />}

                <div style={{ padding: '16px 18px 16px 22px', display: 'flex', justifyContent: 'space-between', gap: '16px' }}>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    {/* Top row */}
                    <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '8px', flexWrap: 'wrap' }}>
                      <RiskBadge level={a.severity} pulse={!a.is_acknowledged} />
                      <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '9px', color: 'var(--text-muted)' }}>#{a.id}</span>
                      {!a.is_acknowledged && (
                        <span style={{ fontFamily: "'Space Mono', monospace", fontSize: '8px', color: c, background: `${c}15`, border: `1px solid ${c}40`, padding: '2px 6px', letterSpacing: '0.1em' }}>NEW</span>
                      )}
                    </div>

                    {/* Message */}
                    <div style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '12px', color: a.is_acknowledged ? 'var(--text-dim)' : 'var(--text-primary)', marginBottom: '10px', lineHeight: '1.5' }}>
                      {a.message}
                    </div>

                    {/* Meta */}
                    <div style={{ display: 'flex', flexWrap: 'wrap', gap: '14px' }}>
                      {[
                        ['HOST', a.hostname], ['USER', a.username],
                        ['DEVICE', a.device_name], ['DRIVE', a.drive_letter],
                        ['TIME', a.created_at ? new Date(a.created_at).toLocaleString() : null],
                      ].filter(([, v]) => v && v !== 'unknown').map(([k, v]) => (
                        <div key={k} style={{ display: 'flex', gap: '6px' }}>
                          <span style={{ fontFamily: "'Space Mono', monospace", fontSize: '8px', color: 'var(--text-muted)', letterSpacing: '0.12em' }}>{k}</span>
                          <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '10px', color: 'var(--text-dim)' }}>{v}</span>
                        </div>
                      ))}
                    </div>
                  </div>

                  {!a.is_acknowledged && (
                    <button className="btn btn-primary" style={{ alignSelf: 'flex-start', whiteSpace: 'nowrap', padding: '6px 14px', fontSize: '9px' }} onClick={() => ack(a.id)}>
                      ✓ ACK
                    </button>
                  )}
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}
